:root {
  --bg-color: #f4f7f6;
  --card-bg: #ffffff;
  --primary: #2c3e50;
  --accent: #3498db;
  --text: #333;
  --border: #ddd;
}

body {
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  background-color: var(--bg-color);
  color: var(--text);
  margin: 0;
  padding: 20px;
}

.dashboard {
  margin: 0 auto;
}

header {
  text-align: center;
  margin-bottom: 30px;
  color: var(--primary);
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 20px;
  margin-bottom: 40px;
}

.card {
  background: var(--card-bg);
  padding: 20px;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  text-align: center;
  border-top: 4px solid var(--accent);
}

.card h3 {
  margin: 0;
  font-size: 1.2rem;
  color: #7f8c8d;
  text-transform: uppercase;
}

.card p {
  font-size: 2rem;
  font-weight: bold;
  margin: 10px 0 0;
}

.table-container {
  background: var(--card-bg);
  padding: 20px;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  overflow-x: auto;
}

table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 10px;
}

th, td {
  text-align: left;
  padding: 12px;
  border-bottom: 1px solid var(--border);
}

th {
  background-color: #f8f9fa;
  color: var(--primary);
}

tr:hover {
  background-color: #f1f1f1;
}

/* Badge Styles */
.badge {
  padding: 4px 8px;
  border-radius: 4px;
  font-size: 1.2rem;
  font-weight: bold;
  display: inline-block;
  min-width: 60px;
  text-align: center;
}

.badge-yes {
  background: #d4edda;
  color: #155724;
  border: 1px solid #c3e6cb;
}

.badge-no {
  background: #f8d7da;
  color: #721c24;
  border: 1px solid #f5c6cb;
}

/* Risk Levels */
.risk-critical {
  color: #e74c3c;
  font-weight: bold;
}

.risk-high {
  color: #e67e22;
  font-weight: bold;
}

.risk-low {
  color: #27ae60;
}

code {
  background: #eee;
  padding: 2px 4px;
  border-radius: 3px;
  font-family: monospace;
  color: #c0392b;
}

/* Protection Status */
.prot-robust {
  color: #27ae60;
}

.prot-vulnerable {
  color: #e74c3c;
}

