appsmith.onReady(() => {
  handlePolicyConsolidation();
});
appsmith.onModelChange(() => {
  handlePolicyConsolidation();
});
function handlePolicyConsolidation() {
  const model = appsmith.model;
  if (!model) return;
  const cookies = model.cookies || [];
  const networkEvents = model.networkEvents || [];
  const policy = model.policy_data?.data || {};
  const mapping = policy.technical_data_disclosures?.device_info?.dashboard_key_mapping || {};
  let mismatches = [];
  let gapCount = 0;
  let shadowCount = 0;
  let totalExfiltratedSize = 0;

  // --- 1. Evaluate Client-Side Data Eligibility Drift (Cookies) ---
  cookies.forEach(cookie => {
    const key = cookie.name;
    let isDisclosed = false;
    if (mapping[key] && !mapping[key].includes("Not explicitly listed")) {
      isDisclosed = true;
    } else if (key === '_cfuvid') {
      isDisclosed = true;
    }
    if (!isDisclosed) {
      gapCount++;
      let type = "Technical";
      if (key.includes('rev_cid')) type = "Behavioral Profiling";
      if (key.includes('geo')) type = "Training Metadata";

      // Exclude pure security cookies from raising active drift alarms
      if (!key.includes('cf')) {
        mismatches.push({
          entity: key,
          layer: "Client-Side Storage",
          activity: type,
          contradiction: "Undisclosed in Privacy Notice",
          status: "Policy Drift",
          statusClass: "warning"
        });
      }
    }
  });

  // --- 2. Evaluate Network Flow Governance (Shadow AI / Ad Handlers) ---
  const aiVendors = ["openai", "anthropic", "claude", "mistral", "googletagmanager", "googlesyndication"];
  const uniqueDomains = new Set();
  networkEvents.forEach(event => {
    if (event.method === "Network.requestWillBeSent") {
      const urlStr = event.params.request.url;
      let domain = "unknown";
      try {
        domain = new URL(urlStr).hostname;
      } catch (e) {
        domain = urlStr;
      }
      if (aiVendors.some(vendor => domain.includes(vendor))) {
        const headers = event.params.request.headers || {};
        const size = parseInt(headers['Content-Length'] || headers['content-length'] || 0);
        totalExfiltratedSize += size;

        // Track unique domains to avoid flooding the concise table
        if (!uniqueDomains.has(domain)) {
          uniqueDomains.add(domain);
          shadowCount++;
          let riskCategory = "General Metadata";
          let contradiction = "Section 3 (Unauthorized Egress)";
          if (domain.includes("googlesyndication")) {
            riskCategory = "Ad Profiling / Synthesis";
            contradiction = "Third Party Egress Rule (Advertising)";
          } else if (size > 2000) {
            riskCategory = "LLM Training Ingestion";
            contradiction = "AI Audit: No Training Clause";
          }
          mismatches.push({
            entity: domain,
            layer: "Network Egress",
            activity: riskCategory,
            contradiction: contradiction,
            status: "Active Violation",
            statusClass: "critical"
          });
        }
      }
    }
  });

  // --- 3. Render UI Components ---

  // Update Stats
  document.getElementById('gap-count').textContent = gapCount;
  document.getElementById('shadow-count').textContent = shadowCount;
  document.getElementById('shadow-vol').textContent = (totalExfiltratedSize / 1024).toFixed(1) + " KB";

  // Update Verdict
  const totalRisks = gapCount + shadowCount;
  const verdictEl = document.getElementById('verdict-status');
  verdictEl.textContent = totalRisks > 0 ? "Drift Detected" : "Compliant";
  verdictEl.style.color = totalRisks > 0 ? "#e74c3c" : "#27ae60";

  // Update Summary Paragraph
  const summaryEl = document.getElementById('drift-summary');
  if (totalRisks > 0) {
    summaryEl.innerHTML = `<strong>Observed divergence detected.</strong> We identified <strong>${gapCount} undisclosed storage indicators</strong> and <strong>${shadowCount} unsanctioned network egress flows</strong>. These activities bypass declared privacy constraints, resulting in <strong>${(totalExfiltratedSize / 1024).toFixed(1)} KB</strong> of observed shadow data volume.`;
    summaryEl.style.borderLeftColor = "#e74c3c";
    summaryEl.style.backgroundColor = "#fdf2f0";
  } else {
    summaryEl.innerHTML = `<strong>✅ Operational Reality Aligns with Stated Policy.</strong> No significant data flow divergence or unsanctioned AI vendor egress observed during the current session.`;
    summaryEl.style.borderLeftColor = "#27ae60";
    summaryEl.style.backgroundColor = "#eafaf1";
  }

  // Render Concise Table
  const tbody = document.getElementById('mismatch-body');
  tbody.innerHTML = "";
  if (mismatches.length === 0) {
    tbody.innerHTML = `<tr><td colspan="5" style="text-align:center; padding: 2rem; color: #7f8c8d;">No drift or violations detected.</td></tr>`;
    return;
  }
  mismatches.forEach(item => {
    const row = document.createElement('tr');
    const bgBadge = item.statusClass === 'critical' ? '#fce4e4' : '#fcf3cf';
    const textBadge = item.statusClass === 'critical' ? '#c0392b' : '#d35400';
    row.innerHTML = `
            <td style="padding: 12px; border-bottom: 1px solid #eee;"><code>${item.entity}</code></td>
            <td style="padding: 12px; border-bottom: 1px solid #eee; color: #555;">${item.layer}</td>
            <td style="padding: 12px; border-bottom: 1px solid #eee;"><strong>${item.activity}</strong></td>
            <td style="padding: 12px; border-bottom: 1px solid #eee; color: #7f8c8d;">${item.contradiction}</td>
            <td style="padding: 12px; border-bottom: 1px solid #eee;">
                <span style="padding: 4px 8px; border-radius: 12px; font-size: 0.75rem; font-weight: bold; background-color: ${bgBadge}; color: ${textBadge};">${item.status}</span>
            </td>
        `;
    tbody.appendChild(row);
  });
}

